const designImportMigration=require("../../../../design_import_migration");const kpFoundryServices=require("../foundryServices");const fsConstants=require("../constants");const logr=designImportMigration.getMxgoUtils().utilFunctions.logr;const i18next=designImportMigration.getMxgoUtils().utilFunctions.i18next;logr.debug("Loading keepServices...");async function getSchema(o,s,r){try{const t=await new Promise(async function(t,e){const n={NSFPATH:s,SCHEMANAME:r};const i=await kpFoundryServices.getIntegrationServiceKeep(o,fsConstants.INT_SERVICE_KEEPAPI_OP.GET_SCHEMA,n);if(i&&i.httpStatusCode===200){t(i)}else{logr.debug(`${i18next.t("design_import.mxgo")} failed to call DRAPI getSchema ${JSON.stringify(i)}`);t(i)}});return t}catch(t){logr.debug(`${i18next.t("design_import.mxgo")} failed to call DRAPI getSchema ${t}`);return false}}async function getListOfScopes(i){try{var t=await new Promise(async function(t,e){const n=await kpFoundryServices.getIntegrationServiceKeep(i,fsConstants.INT_SERVICE_KEEPAPI_OP.LIST_SCOPES);if(n&&n.httpStatusCode===200){t(n)}else{logr.debug(`${i18next.t("design_import.mxgo")} failed to call DRAPI getListOfScopes ${JSON.stringify(n)}`);t(n)}});return t}catch(t){logr.debug(`${i18next.t("design_import.mxgo")} failed to call DRAPI getListOfScopes ${t}`);return false}}async function getDxl(s,r){try{let t=await new Promise(async function(t,e){let n={SCOPE:r};let i=fsConstants.INT_SERVICE_KEEPAPI_XML_OP.GET_DXL_V107;const o=await kpFoundryServices.getIntegrationServiceKeep(s,i,n);if(o&&o.httpresponse?.responsecode===200){t(o)}else{logr.debug(`${i18next.t("design_import.mxgo")} failed to call DRAPI getDxl ${JSON.stringify(o)}`);t(o)}});return t}catch(t){logr.debug("Failed to call DRAPI getDxl : "+t);return false}}module.exports={getSchema:getSchema,getListOfScopes:getListOfScopes,getDxl:getDxl};